diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
index c06d5c759634..b949892b606c 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
@@ -3012,6 +3012,35 @@ static Value *foldAndOrOfICmpEqZeroAndICmp(ICmpInst *LHS, ICmpInst *RHS,
 /// Fold (icmp)&(icmp) or (icmp)|(icmp) if possible.
 /// If IsLogical is true, then the and/or is in select form and the transform
 /// must be poison-safe.
+
+static Value *foldIsAddNotOverflow(ICmpInst *Cmp0, ICmpInst *Cmp1, bool IsAnd,
+                                   InstCombiner::BuilderTy &Builder) {
+  ICmpInst::Predicate Pred0 = Cmp0->getPredicate();
+  ICmpInst::Predicate Pred1 = Cmp1->getPredicate();
+  Value *X = Cmp0->getOperand(0);
+
+  if (IsAnd) {
+    if (Pred0 != ICmpInst::ICMP_NE || !match(Cmp0->getOperand(1), m_AllOnes()))
+      return nullptr;
+  } else {
+    if (Pred0 != ICmpInst::ICMP_EQ || !match(Cmp0->getOperand(1), m_AllOnes()))
+      return nullptr;
+  }
+
+  if (match(Cmp1->getOperand(0), m_Add(m_Specific(X), m_One()))) {
+    if (IsAnd && Pred1 == ICmpInst::ICMP_ULE)
+      return Builder.CreateICmpULT(X, Cmp1->getOperand(1));
+    if (!IsAnd && Pred1 == ICmpInst::ICMP_UGT)
+      return Builder.CreateICmpUGE(X, Cmp1->getOperand(1));
+  } else if (match(Cmp1->getOperand(1), m_Add(m_Specific(X), m_One()))) {
+    if (IsAnd && Pred1 == ICmpInst::ICMP_UGE)
+      return Builder.CreateICmpUGT(Cmp1->getOperand(0), X);
+    if (!IsAnd && Pred1 == ICmpInst::ICMP_ULT)
+      return Builder.CreateICmpULE(Cmp1->getOperand(0), X);
+  }
+
+  return nullptr;
+}
 Value *InstCombinerImpl::foldAndOrOfICmps(ICmpInst *LHS, ICmpInst *RHS,
                                           Instruction &I, bool IsAnd,
                                           bool IsLogical) {
@@ -3020,7 +3049,12 @@ Value *InstCombinerImpl::foldAndOrOfICmps(ICmpInst *LHS, ICmpInst *RHS,
   // Fold (iszero(A & K1) | iszero(A & K2)) ->  (A & (K1 | K2)) != (K1 | K2)
   // Fold (!iszero(A & K1) & !iszero(A & K2)) ->  (A & (K1 | K2)) == (K1 | K2)
   // if K1 and K2 are a one-bit mask.
-  if (Value *V = foldAndOrOfICmpsOfAndWithPow2(LHS, RHS, &I, IsAnd, IsLogical))
+  
+  if (Value *V = foldIsAddNotOverflow(LHS, RHS, IsAnd, Builder))
+    return V;
+  if (Value *V = foldIsAddNotOverflow(RHS, LHS, IsAnd, Builder))
+    return V;
+if (Value *V = foldAndOrOfICmpsOfAndWithPow2(LHS, RHS, &I, IsAnd, IsLogical))
     return V;

   ICmpInst::Predicate PredL = LHS->getPredicate(), PredR = RHS->getPredicate();

